import { Command }  from 'commander';
import { Registry } from '../../registry/Registry.js';

export function registryStatusCommand(program: Command): void {
  program
    .command('registry')
    .argument('[action]', 'Action to perform (status)', 'status')
    .description('Show registry status, totals, and recent errors')
    .action((action: string) => {
      if (action !== 'status') {
        console.log(`Unknown action: ${action}. Did you mean "amend registry status"?`);
        return;
      }

      const { total, recent } = Registry.getInstance().status();

      console.log('[amend registry status]\n');
      console.log(`  Total errors    : ${total}`);
      console.log(`  Recent errors   : ${recent.length}\n`);

      if (recent.length > 0) {
        const keyW = 30;
        const msgW = 25;
        console.log(
          '  ' + 'KEY'.padEnd(keyW) + 'MESSAGE'.padEnd(msgW) + 'FILE'
        );

        for (const r of recent) {
          const shortKey = r.key.length > keyW
            ? '…' + r.key.slice(-(keyW - 1))
            : r.key;
          console.log(
            '  ' + shortKey.padEnd(keyW) + r.message.padEnd(msgW) + `${r.filePath}:${r.line}`
          );
        }
      }

      if (total > 0) {
        const all = Registry.getInstance().getAll();

        const classCount: Record<string, number> = {};
        for (const r of all) {
          classCount[r.errorClass] = (classCount[r.errorClass] ?? 0) + 1;
        }
        const topClass = Object.entries(classCount).sort((a, b) => b[1] - a[1])[0];

        const now = Date.now();
        const last24h = all.filter(
          (r) => now - new Date(r.timestamp).getTime() < 86_400_000
        ).length;

        console.log('\n  Analytics:');
        if (topClass) console.log(`    Most common type  : ${topClass[0]} (${topClass[1]}x)`);
        console.log(`    Last 24h          : ${last24h} errors`);
      }
    });
}
